def collapse_delims(s):
    delimiters = ',; '.split()
    pieces = s.strip().split(delimiters)
    while any((len(piece) < 2 or piece[0] in delimiters and piece[-1] in delimiters,) for piece in pieces):
        # Remove consecutive empty pieces at start and end of each piece
        pieces = [piece[1:-1] for piece in [p for p in ([p.strip() for p in pieces] if len(p)) if not any((len(sub_piece) < 2 or sub_piece[0] in delimiters and sub_piece[-1] in delimiters,) for sub_piece in [sub.split() for sub in piece.split(delimiters) if sub]))]
    return ', '.join(pieces) + ('' if not pieces else ',')
